<?php

declare(strict_types=1);

$pageTitle='Media Pipeline';
$pageDescription='Protected storage, resumable ingestion, processing jobs, HLS delivery, waveform generation, CDN readiness, and media health.';
$pageClass='membership-page admin-catalog-page media-pipeline-page';
require_once __DIR__.'/../includes/admin_catalog.php';
require_once __DIR__.'/../includes/media_pipeline.php';

if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){
    if(!sf_verify_csrf($_POST['csrf_token']??null)){sf_admin_flash('error','Security check failed.');sf_admin_redirect();}
    $action=(string)($_POST['action']??'');
    if($action==='enqueue_job'){
        $objectId=sf_admin_int($_POST['object_id']??null,0)??0;$jobType=trim((string)($_POST['job_type']??''));$result=sf_mp_enqueue_job($objectId,$jobType,50);
        sf_admin_flash(!empty($result['ok'])?'success':'error',!empty($result['ok'])?'Processing job queued.':'Processing job could not be queued: '.($result['error']??'unknown error'));
    }elseif($action==='retry_job'){
        $jobId=sf_admin_int($_POST['job_id']??null,0)??0;
        $ok=$jobId>0&&sf_admin_execute("UPDATE media_processing_jobs SET status='retry',run_after=NOW(),locked_until=NULL,lock_token=NULL,error_message=NULL WHERE id=? AND status='failed'",[$jobId]);
        sf_admin_flash($ok?'success':'error',$ok?'Failed job returned to the queue.':'Job could not be retried.');
    }elseif($action==='set_primary'){
        $ok=sf_mp_set_primary(sf_admin_int($_POST['object_id']??null,0)??0);sf_admin_flash($ok?'success':'error',$ok?'Primary media object updated.':'Object could not be updated.');
    }elseif($action==='delete_object'){
        $objectId=sf_admin_int($_POST['object_id']??null,0)??0;$confirmation=trim((string)($_POST['confirmation']??''));$object=sf_mp_object_by_id($objectId);
        $ok=$object&&hash_equals((string)$object['object_key'],$confirmation)&&sf_mp_mark_object($objectId,'deleted',['deleted_by'=>sf_current_user_id()]);
        sf_admin_flash($ok?'success':'error',$ok?'Media object retired from delivery.':'Enter the exact object key to retire it.');
    }elseif($action==='expire_sessions'){
        $count=sf_mp_expire_upload_sessions(1000);sf_admin_flash('success',$count.' expired upload session(s) cleaned.');
    }elseif($action==='run_health'){
        $result=sf_mp_run_storage_health_check();sf_admin_flash(!empty($result['ok'])?'success':'error','Storage health: '.($result['status']??$result['error']??'unknown').'.');
    }
    sf_admin_redirect(sf_url('admin/media-pipeline.php'));
}

$provider=sf_mp_provider_summary();$usage=sf_mp_storage_usage_summary();$queue=sf_mp_queue_summary();$delivery=sf_mp_delivery_summary();
$objects=sf_admin_table_exists('media_objects')?sf_admin_fetch_all('SELECT mo.*,msp.driver,msp.provider_key FROM media_objects mo JOIN media_storage_providers msp ON msp.id=mo.provider_id ORDER BY mo.id DESC LIMIT 100'):[];
$jobs=sf_admin_table_exists('media_processing_jobs')?sf_admin_fetch_all('SELECT mpj.*,mo.entity_type,mo.entity_id,mo.role FROM media_processing_jobs mpj JOIN media_objects mo ON mo.id=mpj.object_id ORDER BY mpj.id DESC LIMIT 100'):[];
$uploads=sf_admin_table_exists('media_upload_sessions')?sf_admin_fetch_all('SELECT * FROM media_upload_sessions ORDER BY id DESC LIMIT 50'):[];
$health=sf_admin_table_exists('media_storage_health_runs')?sf_admin_fetch_all('SELECT msh.*,msp.provider_key FROM media_storage_health_runs msh JOIN media_storage_providers msp ON msp.id=msh.provider_id ORDER BY msh.id DESC LIMIT 20'):[];
$songs=sf_admin_songs();$videos=sf_admin_videos();$csrf=sf_csrf_token();
require __DIR__.'/../includes/header.php';
sf_admin_shell_start('Secure Media','Protected Media Storage, CDN & Transcoding','Upload protected masters, create previews and waveforms, package adaptive HLS video, monitor storage, and audit member delivery.','media-pipeline');
?>
