<section class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Processing Queue</span><h2><?= count($jobs) ?> recent jobs</h2></div></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Job</th><th>Object</th><th>Type</th><th>Progress</th><th>Attempts</th><th>Status</th><th>Error</th><th></th></tr></thead><tbody><?php foreach($jobs as $job): ?><tr><td><strong>#<?= (int)$job['id'] ?></strong><small class="mp-code"><?= sf_admin_h($job['job_key']) ?></small></td><td><?= sf_admin_h($job['entity_type'].' #'.$job['entity_id'].' · '.$job['role']) ?></td><td><?= sf_admin_h($job['job_type']) ?></td><td><?= (int)$job['progress_percent'] ?>%</td><td><?= (int)$job['attempts'] ?>/<?= (int)$job['max_attempts'] ?></td><td><?= sf_admin_status_badge((string)$job['status']) ?></td><td><?= sf_admin_h($job['error_message']??'—') ?></td><td><?php if(($job['status']??'')==='failed'): ?><form method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="retry_job"><input type="hidden" name="job_id" value="<?= (int)$job['id'] ?>"><button>Retry</button></form><?php endif; ?></td></tr><?php endforeach; ?><?php if(!$jobs): ?><tr><td colspan="8">No processing jobs yet.</td></tr><?php endif; ?></tbody></table></div></section>
<section class="sf-admin-two-col sf-admin-two-col-wide"><article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Upload Sessions</span><h2>Recent ingestion</h2></div></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>File</th><th>Entity</th><th>Chunks</th><th>Bytes</th><th>Status</th></tr></thead><tbody><?php foreach($uploads as $upload): ?><tr><td><strong><?= sf_admin_h($upload['original_filename']) ?></strong></td><td><?= sf_admin_h($upload['entity_type'].' #'.$upload['entity_id']) ?></td><td><?= (int)$upload['received_chunks'] ?>/<?= (int)$upload['expected_chunks'] ?></td><td><?= sf_admin_format_bytes((int)$upload['received_size_bytes']) ?> / <?= sf_admin_format_bytes((int)$upload['expected_size_bytes']) ?></td><td><?= sf_admin_status_badge((string)$upload['status']) ?></td></tr><?php endforeach; ?><?php if(!$uploads): ?><tr><td colspan="5">No upload sessions yet.</td></tr><?php endif; ?></tbody></table></div></article><article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Provider Health</span><h2>Read/write/delete evidence</h2></div></div><div class="sf-admin-table-wrap"><table class="sf-admin-table"><thead><tr><th>Provider</th><th>Status</th><th>R/W/D</th><th>Latency</th><th>Completed</th></tr></thead><tbody><?php foreach($health as $run): ?><tr><td><?= sf_admin_h($run['provider_key']) ?></td><td><?= sf_admin_status_badge((string)$run['status']) ?></td><td><?= sf_admin_h($run['read_test_status'].' / '.$run['write_test_status'].' / '.$run['delete_test_status']) ?></td><td><?= (int)$run['latency_ms'] ?> ms</td><td><?= sf_admin_h($run['completed_at']??'—') ?></td></tr><?php endforeach; ?><?php if(!$health): ?><tr><td colspan="5">No health run recorded.</td></tr><?php endif; ?></tbody></table></div></article></section>
<script>
(()=>{const form=document.getElementById('mediaPipelineUpload');if(!form)return;const status=document.getElementById('mediaUploadStatus');const bar=document.getElementById('mediaUploadBar');const csrf=<?= json_encode($csrf) ?>;const sha=async blob=>{const buf=await blob.arrayBuffer();const hash=await crypto.subtle.digest('SHA-256',buf);return [...new Uint8Array(hash)].map(b=>b.toString(16).padStart(2,'0')).join('')};form.addEventListener('submit',async e=>{e.preventDefault();const file=form.media_file.files[0];if(!file)return;try{status.textContent='Creating protected upload session…';const init=await fetch(<?= json_encode(sf_url('api/media-upload-init.php')) ?>,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({csrf_token:csrf,entity_type:form.entity_type.value,entity_id:Number(form.entity_id.value),target_role:form.target_role.value,filename:file.name,mime_type:file.type||'application/octet-stream',size_bytes:file.size})}).then(r=>r.json());if(!init.ok)throw new Error(init.error||'Session failed');for(let part=0;part<init.expected_chunks;part++){const start=part*init.chunk_size_bytes,end=Math.min(file.size,start+init.chunk_size_bytes),chunk=file.slice(start,end),digest=await sha(chunk);status.textContent=`Uploading chunk ${part+1} of ${init.expected_chunks}…`;const response=await fetch(<?= json_encode(sf_url('api/media-upload-chunk.php')) ?>+`?session=${encodeURIComponent(init.session_token)}&part=${part}`,{method:'PUT',headers:{'X-Stonefellow-CSRF':csrf,'X-Chunk-SHA256':digest,'Content-Type':'application/octet-stream'},body:chunk}).then(r=>r.json());if(!response.ok)throw new Error(response.error||'Chunk failed');bar.style.width=Math.round(((part+1)/init.expected_chunks)*90)+'%'}status.textContent='Verifying checksum, registering master, and creating processing jobs…';const complete=await fetch(<?= json_encode(sf_url('api/media-upload-complete.php')) ?>,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({csrf_token:csrf,session_token:init.session_token})}).then(r=>r.json());if(!complete.ok)throw new Error(complete.error||'Completion failed');bar.style.width='100%';status.textContent=`Upload complete. Media object #${complete.object_id}. Jobs: ${(complete.queued_jobs||[]).join(', ')||'none'}.`;setTimeout(()=>location.reload(),1500)}catch(error){status.textContent='Upload failed: '+error.message;bar.style.width='0%'}})})();
</script>
